'use client';

import { useUser } from '@insforge/nextjs';
import { insforge } from '@/lib/insforge';
import { useState, useEffect } from 'react';
import { Camera, Edit2, Trash2 } from 'lucide-react';
import Link from 'next/link';

export default function Dashboard() {
    const { user, isLoaded } = useUser();
    const [name, setName] = useState('');
    const [bio, setBio] = useState('');
    const [avatarUrl, setAvatarUrl] = useState('');
    const [isUploading, setIsUploading] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    const [posts, setPosts] = useState<any[]>([]);
    const [loadingPosts, setLoadingPosts] = useState(true);

    useEffect(() => {
        if (user) {
            // Sync or fetch profile
            insforge.database.from('profiles').select('*').eq('id', user.id).single().then(({ data }) => {
                if (data) {
                    setName(data.name || '');
                    setBio(data.bio || '');
                    setAvatarUrl(data.avatar_url || '');
                } else {
                    const profileData = {
                        id: user.id,
                        name: user.profile?.name || user.email?.split('@')[0] || 'User',
                        email: user.email || '',
                        avatar_url: user.profile?.avatar_url || ''
                    };
                    insforge.database.from('profiles').insert(profileData).then(() => {
                        setName(profileData.name);
                        setAvatarUrl(profileData.avatar_url);
                    });
                }
            });

            // Fetch user's posts
            fetchPosts();
        }
    }, [user]);

    const fetchPosts = async () => {
        if (!user) return;
        setLoadingPosts(true);
        const { data } = await insforge.database
            .from('posts')
            .select('id, title, is_draft, created_at')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });
        if (data) setPosts(data);
        setLoadingPosts(false);
    };

    const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setIsUploading(true);
        const { data } = await insforge.storage.from('avatars').uploadAuto(file);
        if (data?.url) {
            setAvatarUrl(data.url);
        }
        setIsUploading(false);
    };

    const handleSave = async () => {
        if (!user) return;
        setIsSaving(true);
        await insforge.database.from('profiles').update({ name, bio, avatar_url: avatarUrl }).eq('id', user.id);
        await insforge.auth.setProfile({ name, avatar_url: avatarUrl, bio });
        setIsSaving(false);
    };

    const handleDeletePost = async (id: string) => {
        if (!confirm('Are you sure you want to delete this post?')) return;
        await insforge.database.from('posts').delete().eq('id', id);
        fetchPosts();
    };

    if (!isLoaded) return <div className="p-10 text-center">Loading...</div>;
    if (!user) return <div className="p-10 text-center">Please sign in to view your dashboard.</div>;

    return (
        <div className="max-w-4xl mx-auto px-6 py-12 grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="md:col-span-1 space-y-6">
                <h1 className="text-2xl font-bold mb-4">Profile</h1>
                <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-sm space-y-4">
                    <div className="flex flex-col items-center">
                        <div className="relative mb-4">
                            <div className="w-32 h-32 rounded-full bg-gray-200 overflow-hidden border border-gray-300 flex items-center justify-center">
                                {avatarUrl ? (
                                    // eslint-disable-next-line @next/next/no-img-element
                                    <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-gray-400 text-sm">No Image</span>
                                )}
                            </div>
                            <label className="absolute bottom-1 right-1 bg-[#1a1a2e] text-white p-2 rounded-full cursor-pointer hover:bg-black transition-colors">
                                <Camera className="w-4 h-4" />
                                <input type="file" className="hidden" accept="image/*" onChange={handleAvatarUpload} disabled={isUploading} />
                            </label>
                        </div>
                        {isUploading && <p className="text-xs text-blue-500 mb-2">Uploading...</p>}
                        <div className="w-full text-left font-medium">
                            <label className="block text-xs text-gray-500 uppercase tracking-widest mb-1">Name</label>
                            <input
                                type="text"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                className="w-full p-2 border-b border-gray-300 bg-transparent focus:border-[#1a1a2e] outline-none transition-colors"
                            />
                        </div>
                        <div className="w-full text-left font-medium mt-4">
                            <label className="block text-xs text-gray-500 uppercase tracking-widest mb-1">Bio</label>
                            <textarea
                                value={bio}
                                onChange={e => setBio(e.target.value)}
                                rows={3}
                                className="w-full p-2 border-b border-gray-300 bg-transparent focus:border-[#1a1a2e] outline-none transition-colors resize-none"
                            />
                        </div>
                    </div>
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        className="w-full bg-[#1a1a2e] text-white px-4 py-2 rounded-full font-medium hover:bg-black transition-colors disabled:opacity-50 flex justify-center items-center"
                    >
                        {isSaving ? "Saving..." : <><Edit2 className="w-4 h-4 mr-2" /> Save</>}
                    </button>
                </div>
            </div>

            <div className="md:col-span-2">
                <div className="flex justify-between items-center mb-6">
                    <h1 className="text-2xl font-bold">Your Stories</h1>
                    <Link href="/new" className="bg-[#1a1a2e] text-white px-4 py-2 rounded-full text-sm font-medium hover:bg-black transition-colors">Write a story</Link>
                </div>

                <div className="space-y-4">
                    {loadingPosts && <p className="text-gray-500">Loading stories...</p>}
                    {!loadingPosts && posts.length === 0 && (
                        <div className="bg-white p-8 rounded-lg border border-gray-200 text-center">
                            <p className="text-gray-500 mb-4">You haven&apos;t written any stories yet.</p>
                            <Link href="/new" className="text-[#1a1a2e] font-semibold hover:underline">Start writing</Link>
                        </div>
                    )}
                    {posts.map(post => (
                        <div key={post.id} className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm flex justify-between items-center group">
                            <div>
                                <Link href={`/p/${post.id}`} className="font-bold text-lg hover:underline decoration-2 text-[#1a1a2e]">
                                    {post.title || 'Untitled Story'}
                                </Link>
                                <div className="flex items-center text-sm text-gray-500 mt-1 space-x-3">
                                    <span>{new Date(post.created_at).toLocaleDateString()}</span>
                                    {post.is_draft ? (
                                        <span className="text-amber-600 bg-amber-50 px-2 py-0.5 rounded text-xs font-medium">Draft</span>
                                    ) : (
                                        <span className="text-green-600 bg-green-50 px-2 py-0.5 rounded text-xs font-medium">Published</span>
                                    )}
                                </div>
                            </div>
                            <div className="flex items-center space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                <Link href={`/edit/${post.id}`} className="p-2 text-gray-500 hover:text-[#1a1a2e] transition-colors rounded-full hover:bg-gray-100">
                                    <Edit2 className="w-5 h-5" />
                                </Link>
                                <button
                                    onClick={() => handleDeletePost(post.id)}
                                    className="p-2 text-gray-500 hover:text-red-500 transition-colors rounded-full hover:bg-red-50"
                                >
                                    <Trash2 className="w-5 h-5" />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useParams } from 'next/navigation';
import { useEffect, useState } from 'react';
import PostEditor from '@/components/PostEditor';
import { insforge } from '@/lib/insforge';

export default function EditPost() {
    const { id } = useParams();
    const [post, setPost] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (id) {
            insforge.database.from('posts').select('*').eq('id', id).single().then(({ data }) => {
                setPost(data);
                setLoading(false);
            });
        }
    }, [id]);

    if (loading) return <div className="p-10 text-center">Loading editor...</div>;
    if (!post) return <div className="p-10 text-center">Post not found</div>;

    return <PostEditor initialPost={post} />;
}

import { insforge } from '@/lib/insforge';
import Link from 'next/link';
import { auth } from '@insforge/nextjs/server';

export const revalidate = 0;

export default async function Home(props: { searchParams?: Promise<{ [key: string]: string | string[] | undefined }> }) {
  const { user } = await auth().catch(() => ({ user: null }));
  const searchParams = await props.searchParams;
  const feed = searchParams?.feed || 'explore';
  const showFollowing = feed === 'following' && user;

  let query = insforge.database
    .from('posts')
    .select('*, profiles:user_id(name, avatar_url)')
    .eq('is_draft', false)
    .order('created_at', { ascending: false })
    .limit(20);

  if (showFollowing && user) {
    const { data: follows } = await insforge.database.from('follows').select('following_id').eq('follower_id', user.id);
    const followingIds = follows?.map(f => f.following_id) || [];
    if (followingIds.length > 0) {
      query = query.in('user_id', followingIds);
    } else {
      query = query.in('user_id', ['00000000-0000-0000-0000-000000000000']);
    }
  }

  const { data: posts, error } = await query;

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="mb-12 border-b border-gray-300 pb-12">
        <h1 className="text-5xl md:text-7xl font-bold tracking-tighter mb-6 text-[#1a1a2e]">
          Inkwell.
        </h1>
        <p className="text-xl md:text-2xl text-gray-700 max-w-2xl leading-snug">
          Discover stories, independent thinking, and expertise from writers everywhere.
        </p>
      </div>

      <div className="flex items-center space-x-6 mb-8 border-b border-gray-200">
        <Link href="/" className={`pb-3 font-medium border-b-2 ${!showFollowing ? 'border-[#1a1a2e] text-[#1a1a2e]' : 'border-transparent text-gray-500 hover:text-gray-800'}`}>
          Explore
        </Link>
        {user && (
          <Link href="/?feed=following" className={`pb-3 font-medium border-b-2 ${showFollowing ? 'border-[#1a1a2e] text-[#1a1a2e]' : 'border-transparent text-gray-500 hover:text-gray-800'}`}>
            For you
          </Link>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {!posts && !error && <div className="col-span-full py-20 text-center text-gray-500">Loading...</div>}
        {error && <div className="col-span-full py-20 text-center text-red-500">Failed to load posts</div>}
        {posts?.length === 0 && (
          <div className="col-span-full py-20 text-center text-gray-600 bg-white rounded-xl border border-gray-200 p-8 shadow-sm">
            <h3 className="text-2xl font-semibold mb-2">No posts here yet</h3>
            <p className="mb-6">{showFollowing ? "People you follow haven't posted." : "Be the first to share your thoughts."}</p>
            <Link href="/new" className="bg-[#1a1a2e] text-white px-6 py-2.5 rounded-full font-medium hover:bg-black transition-colors inline-block">
              Start writing
            </Link>
          </div>
        )}
        {posts?.map((post: any) => (
          <article key={post.id} className="flex flex-col bg-white rounded-xl overflow-hidden border border-gray-200 group hover:shadow-lg transition-all duration-300">
            <Link href={`/p/${post.id}`} className="block h-48 bg-gray-100 w-full relative border-b border-gray-200 overflow-hidden">
              {post.cover_image_url ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img src={post.cover_image_url} alt={post.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
              ) : (
                <div className="w-full h-full bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center text-gray-400 group-hover:scale-105 transition-transform duration-700 font-serif italic">
                  Read story
                </div>
              )}
            </Link>
            <div className="p-6 flex flex-col flex-1">
              <Link href={`/u/${post.user_id}`} className="flex items-center space-x-2 mb-3 hover:opacity-80">
                <div className="w-6 h-6 rounded-full bg-gray-200 overflow-hidden">
                  {post.profiles?.avatar_url && (
                    // eslint-disable-next-line @next/next/no-img-element
                    <img src={post.profiles.avatar_url} alt="" className="w-full h-full object-cover" />
                  )}
                </div>
                <span className="text-sm font-medium text-gray-700">{post.profiles?.name || 'Unknown'}</span>
              </Link>
              <Link href={`/p/${post.id}`}>
                <h2 className="text-2xl font-bold leading-tight mb-3 group-hover:text-blue-700 transition-colors line-clamp-2 text-[#1a1a2e]">{post.title}</h2>
                <div className="text-gray-600 line-clamp-3 text-sm leading-relaxed mb-4" dangerouslySetInnerHTML={{ __html: post.content || '' }}></div>
              </Link>
              <div className="mt-auto pt-4 flex items-center justify-between text-xs text-gray-500 border-t border-gray-100">
                <span>{new Date(post.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                <span className="bg-gray-100 px-2 py-1 rounded">Read</span>
              </div>
            </div>
          </article>
        ))}
      </div>
    </div>
  );
}

